const row = $input.first().json;
function parsePrices(raw) {
  if (!raw) return [];
  if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { return []; } }
  return Array.isArray(raw) ? raw : [];
}
function fmtPct(v) {
  const n = parseFloat(v);
  return (!v || isNaN(n) || n === 0) ? null : n.toFixed(0) + '%';
}
function fmtC(v) {
  const n = parseFloat(v);
  if (!v || isNaN(n)) return null;
  return (n >= 0 ? '+' : '') + n.toFixed(0) + 'C';
}
function fmtScu(v) {
  const n = parseFloat(v);
  if (!v || isNaN(n) || n === 0) return null;
  if (n >= 1000000) return (n/1000000).toFixed(3).replace(/\.?0+$/,'') + ' SCU';
  return (n/1000).toFixed(3).replace(/\.?0+$/,'') + ' mSCU';
}
const uex  = parsePrices(row.uex_prices);
const dp4k = parsePrices(row.datap4k_prices);
const lines = [];
lines.push('# ' + row.name);
lines.push('');
lines.push('- **Slot:** ' + (row.slot || 'Unknown'));
const cat = row.uex_category_name || row.slot || 'Armor';
lines.push('- **Category:** ' + cat);
if (row.uex_category_section && row.uex_category_section !== cat)
  lines.push('- **Section:** ' + row.uex_category_section);
if (row.tier) lines.push('- **Tier:** ' + row.tier.charAt(0).toUpperCase() + row.tier.slice(1));
if (row.manufacturer) lines.push('- **Manufacturer:** ' + row.manufacturer);
const DMG = [
  ['dmg_res_physical','Physical'],['dmg_res_energy','Energy'],
  ['dmg_res_distortion','Distortion'],['dmg_res_biochemical','Biochemical'],
  ['dmg_res_stun','Stun'],['dmg_res_force','Force'],['dmg_res_thermal','Thermal']
];
const dmgRows = DMG.map(([col,label]) => [label, fmtPct(row[col])]).filter(([,v]) => v);
if (dmgRows.length) {
  lines.push(''); lines.push('## Damage Resistance');
  lines.push('| Type | Resistance |'); lines.push('|---|---|');
  dmgRows.forEach(([l,v]) => lines.push(`| ${l} | ${v} |`));
}
const envLines = [];
const tMin = fmtC(row.temp_min_c), tMax = fmtC(row.temp_max_c);
if (tMin && tMax) envLines.push(`- **Temperature Range:** ${tMin} to ${tMax}`);
if (parseFloat(row.rad_capacity) > 0) envLines.push(`- **Radiation Capacity:** ${parseInt(row.rad_capacity).toLocaleString()}`);
const scu = fmtScu(row.micro_scu);
if (scu) envLines.push('- **Inventory:** ' + scu);
if (envLines.length) { lines.push(''); lines.push('## Environmental & Storage'); envLines.forEach(l => lines.push(l)); }
const sigLines = [];
if (parseFloat(row.sig_ir_emission) > 0) sigLines.push(`- **IR Emission:** ${parseFloat(row.sig_ir_emission).toFixed(0)}`);
if (parseFloat(row.sig_ir_reduce_abs) > 0) sigLines.push(`- **IR Reduction:** ${parseFloat(row.sig_ir_reduce_abs).toFixed(0)}`);
if (parseFloat(row.sig_em_emission) > 0) sigLines.push(`- **EM Emission:** ${parseFloat(row.sig_em_emission).toFixed(0)}`);
if (parseFloat(row.sig_em_reduce_abs) > 0) sigLines.push(`- **EM Reduction:** ${parseFloat(row.sig_em_reduce_abs).toFixed(0)}`);
if (sigLines.length) { lines.push(''); lines.push('## Signature'); sigLines.forEach(l => lines.push(l)); }
if (uex.length) {
  lines.push(''); lines.push('## UEX Prices');
  lines.push('| Terminal | Buy | Sell |'); lines.push('|---|---|---|');
  uex.slice(0,10).forEach(p => {
    const buy  = (p.buy  && p.buy  > 0) ? p.buy.toLocaleString()  + ' aUEC' : '—';
    const sell = (p.sell && p.sell > 0) ? p.sell.toLocaleString() + ' aUEC' : '—';
    lines.push(`| ${p.terminal||'?'} | ${buy} | ${sell} |`);
  });
} else if (dp4k.length) {
  lines.push(''); lines.push('## Shop Prices (DataPack)');
  lines.push('| Shop | Location | Buy |'); lines.push('|---|---|---|');
  dp4k.slice(0,10).forEach(p => {
    const buy = (p.buy && p.buy > 0) ? p.buy.toLocaleString() + ' aUEC' : '—';
    lines.push(`| ${p.shop||'?'} | ${p.location||'?'} | ${buy} |`);
  });
}
return [{ json: { ...row, kb_markdown: lines.join('\n') } }];

const row = $input.first().json;
const slug = row.slug || '';
if (!slug) return [];
return [{ json: {
  entity_slug: slug,
  entity_type: 'armor',
  content: row.kb_markdown || '',
  source_workflow: 'KB - Armor Markdown v1',
} }];
